sql:
SELECT AVG(change_count) AS average_changes
FROM (
  SELECT changed_by, COUNT(*) AS change_count
  FROM frequency_logs
  GROUP BY changed_by
) AS user_changes;

SELECT COUNT(*)
FROM frequencies
WHERE active_status = 1;

SELECT program_name
FROM hd_subchannels
WHERE active = 1;

SELECT station_name
FROM radio_stations
WHERE last_inspection_date LIKE '2023%';

SELECT station_name
FROM radio_stations
WHERE station_id = 1;

SELECT COUNT(*) AS station_count
FROM radio_stations
WHERE regulatory_body = 'FCC';

SELECT station_name 
FROM radio_stations 
ORDER BY station_name ASC;

external_knowledge:
- The term "compliance status" refers to whether a frequency meets the required regulations; 
- "radio frequency hierarchy" implies a structured organization of frequencies based on their relationships; 
- "user access" includes viewing or editing frequency configurations; 
- "most recent compliance statuses and access activities" indicate the latest information available.

sql:
SELECT frequency_integer, frequency_fraction
FROM frequencies
WHERE active_status = 1;

SELECT change_reason
FROM frequency_logs
WHERE change_type = 'update';

SELECT frequency_id, station_id
FROM frequencies
ORDER BY station_id, frequency_id;

SELECT COUNT(report_id) AS report_count
FROM frequency_reports
WHERE generated_by = '1' AND report_type = 'daily';
